-- resilience box-jump slots
INSERT INTO coaching.phase_order_slot (key, name, description, phase_id, order_index, freshness_sensitivity, subrole_key)
SELECT v.key, v.name, v.description, sp.id, v.order_index, v.freshness_sensitivity, v.subrole_key
FROM coaching.session_phase sp
CROSS JOIN (VALUES
  ('landing_stick_foundation', 'Landing Stick Foundation', 'Box Jump Landing & Braking Control — Snap Down to Stick.', 536, 5, 'landing_braking_control'),
  ('landing_braking_control', 'Landing Braking Control', 'Box Jump Landing & Braking Control — Depth Drop to Athletic Stick.', 537, 5, 'landing_braking_control'),
  ('single_leg_landing_control', 'Single Leg Landing Control', 'Box Jump Landing & Braking Control — Single-Leg Depth Drop to Stick.', 538, 5, 'single_leg_balance_foot_ankle_hip_control')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'resilience'
ON CONFLICT (key) DO NOTHING;

