-- Insert 46 new box-jump exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility, participant_structure,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility', d.participant,
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Single-Leg Depth Drop to Stick', 'single-leg-depth-drop-to-stick', 'Single-Leg Depth Drop to Stick is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.', 'INTERMEDIATE', 9, 2, 3, NULL, 45, 35, 'individual', 'Box-jump-focused exercise that progresses landing control to single-leg foot, ankle, knee, and hip alignment. Best used when the coach wants landing control without violating session order.', 'Primary subrole: single_leg_balance_foot_ankle_hip_control. Slot: single_leg_landing_control. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Landing & Braking Control', 'resilience', 'single_leg_balance_foot_ankle_hip_control', 'single_leg_landing_control', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"single_leg","coordination_demand":"high","impact_level":4}'::jsonb, '{"movement_description":"Single-Leg Depth Drop to Stick is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Set up on the working leg with the stance foot rooted and the box low enough to keep the knee tracking clean."],"execution_steps":["Move or drop into the landing with a quiet, controlled foot contact.","Absorb through the ankles, knees, and hips while keeping ribs stacked over pelvis.","Hold the stick for two full seconds before stepping down and resetting."],"coach_cues":["Own the stick before adding height.","Absorb through ankle, knee, and hip together.","No knee cave or torso collapse.","Stop as soon as landings get loud.","Pelvis level; do not let the stance hip dump."],"athlete_cues":["Land soft and freeze.","Knees point the same way as toes.","Hold still before you move.","Balance before the next rep."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Athlete holds the stick for two seconds","Landing is quiet and symmetrical enough for the drill","Athlete can explain or demonstrate the safer step-down reset","Single-leg balance is held without hopping"],"common_faults":["Landing noise increases across reps","Knees cave or feet collapse inward","Athlete cannot hold the stick","Torso folds forward on contact"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('Box Jump Step-Down Reset', 'box-jump-step-down-reset', 'Box Jump Step-Down Reset is a technical box-jump skill drill. The athlete moves at a teachable speed, coordinates the takeoff and landing sequence, and resets every rep so the pattern stays crisp. It prepares the athlete for higher-intent box jumps without turning the set into conditioning.', 'BEGINNER', 4, 2, 4, NULL, 45, 40, 'individual', 'Box-jump-focused exercise that teaches the safest box-jump rhythm: jump up, stick, stand tall, step down, reset before the next rep. Best used when the coach wants technical skill without violating session order.', 'Primary subrole: balance_coordination_rhythm. Slot: box_jump_mechanics. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Movement Intelligence', 'movement_intelligence', 'balance_coordination_rhythm', 'box_jump_mechanics', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Box Jump Step-Down Reset is a technical box-jump skill drill. The athlete moves at a teachable speed, coordinates the takeoff and landing sequence, and resets every rep so the pattern stays crisp. It prepares the athlete for higher-intent box jumps without turning the set into conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Load the hips with control and swing the arms in rhythm with the jump pattern.","Jump or move over the box with enough height to clear safely without rushing.","Land, stand tall, step down, and reset before the next rep."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('Low Box Jump to Stick', 'low-box-jump-to-stick', 'Low Box Jump to Stick is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.', 'INTERMEDIATE', 4, 3, 3, NULL, 90, 45, 'individual', 'Box-jump-focused exercise that introduces explosive box jumping with a low height and a complete landing stick. Best used when the coach wants power expression without violating session order.', 'Primary subrole: jump_throw_explosive_power. Slot: low_box_power_stick. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Explosive Power', 'output', 'jump_throw_explosive_power', 'low_box_power_stick', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":3}'::jsonb, '{"movement_description":"Low Box Jump to Stick is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Load quickly but under control, then drive the floor away with full-body intent.","Land on the box with the whole foot, knees tracking over toes, and chest organized.","Stand tall, step down, and rest long enough for the next rep to be just as explosive."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('Static Squat Jump to Box', 'static-squat-jump-to-box', 'Static Squat Jump to Box is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.', 'INTERMEDIATE', 6, 3, 3, NULL, 90, 45, 'individual', 'Box-jump-focused exercise that builds pure concentric leg drive from a held squat position into a quiet box landing. Best used when the coach wants power expression without violating session order.', 'Primary subrole: jump_throw_explosive_power. Slot: concentric_box_power. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Explosive Power', 'output', 'jump_throw_explosive_power', 'concentric_box_power', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":3}'::jsonb, '{"movement_description":"Static Squat Jump to Box is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Set the start position, pause still for one to two seconds, then jump without a bounce.","Land on the box with the whole foot, knees tracking over toes, and chest organized.","Stand tall, step down, and rest long enough for the next rep to be just as explosive."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('Pause Box Jump', 'pause-box-jump', 'Pause Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.', 'INTERMEDIATE', 6, 3, 3, NULL, 90, 45, 'individual', 'Box-jump-focused exercise that removes the fast countermovement so the athlete must create force from a controlled paused position. Best used when the coach wants power expression without violating session order.', 'Primary subrole: jump_throw_explosive_power. Slot: concentric_box_power. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Explosive Power', 'output', 'jump_throw_explosive_power', 'concentric_box_power', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":3}'::jsonb, '{"movement_description":"Pause Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Set the start position, pause still for one to two seconds, then jump without a bounce.","Land on the box with the whole foot, knees tracking over toes, and chest organized.","Stand tall, step down, and rest long enough for the next rep to be just as explosive."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('No-Arm-Swing Box Jump', 'no-arm-swing-box-jump', 'No-Arm-Swing Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.', 'INTERMEDIATE', 6, 3, 3, NULL, 90, 45, 'individual', 'Box-jump-focused exercise that isolates lower-body impulse and trunk stiffness by taking the arm swing away. Best used when the coach wants power expression without violating session order.', 'Primary subrole: jump_throw_explosive_power. Slot: concentric_box_power. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Explosive Power', 'output', 'jump_throw_explosive_power', 'concentric_box_power', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":3}'::jsonb, '{"movement_description":"No-Arm-Swing Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Hold the arms fixed or lightly crossed, load the hips under control, and jump without arm-swing help.","Land on the box with the whole foot, knees tracking over toes, and chest organized.","Stand tall, step down, and rest long enough for the next rep to be just as explosive."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('Box Jump with Altitude Landing', 'box-jump-with-altitude-landing', 'Box Jump with Altitude Landing is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.', 'INTERMEDIATE', 9, 2, 3, NULL, 45, 35, 'individual', 'Box-jump-focused exercise that pairs an upward jump with a deliberate drop-and-stick to train landing tolerance after box contact. Best used when the coach wants landing control without violating session order.', 'Primary subrole: landing_braking_control. Slot: landing_braking_control. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Landing & Braking Control', 'resilience', 'landing_braking_control', 'landing_braking_control', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"high","impact_level":4}'::jsonb, '{"movement_description":"Box Jump with Altitude Landing is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Move or drop into the landing with a quiet, controlled foot contact.","Absorb through the ankles, knees, and hips while keeping ribs stacked over pelvis.","Hold the stick for two full seconds before stepping down and resetting."],"coach_cues":["Own the stick before adding height.","Absorb through ankle, knee, and hip together.","No knee cave or torso collapse.","Stop as soon as landings get loud."],"athlete_cues":["Land soft and freeze.","Knees point the same way as toes.","Hold still before you move."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Athlete holds the stick for two seconds","Landing is quiet and symmetrical enough for the drill","Athlete can explain or demonstrate the safer step-down reset"],"common_faults":["Landing noise increases across reps","Knees cave or feet collapse inward","Athlete cannot hold the stick","Torso folds forward on contact"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
  ('Countermovement Box Jump', 'countermovement-box-jump', 'Countermovement Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.', 'INTERMEDIATE', 6, 3, 3, NULL, 90, 45, 'individual', 'Box-jump-focused exercise that the primary box-jump expression for bilateral vertical power with an athletic countermovement. Best used when the coach wants power expression without violating session order.', 'Primary subrole: jump_throw_explosive_power. Slot: box_jump_power. Keep box height honest; the box is a target for better mechanics, not an ego test.', 'Jump or land softly, own the box, step down, and make every rep look clean.', 'Box Jump Explosive Power', 'output', 'jump_throw_explosive_power', 'box_jump_power', '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":3}'::jsonb, '{"movement_description":"Countermovement Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Load quickly but under control, then drive the floor away with full-body intent.","Land on the box with the whole foot, knees tracking over toes, and chest organized.","Stand tall, step down, and rest long enough for the next rep to be just as explosive."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb),
