INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), 'primary', m.slot, pos.order_index,
  COALESCE(m.freshness_required, TRUE), COALESCE(m.fatigue_sensitivity, 5), COALESCE(m.fatigue_cost, 3),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 2), COALESCE(m.intensity_ceiling, 'moderate')
FROM (VALUES
  ('single-leg-depth-drop-to-stick', 'resilience', 'single_leg_landing_control', 5, FALSE, 3, 3, 4, 4, 'moderate'),
  ('box-jump-step-down-reset', 'movement_intelligence', 'box_jump_mechanics', 5, TRUE, 3, 2, 3, 2, 'moderate'),
  ('low-box-jump-to-stick', 'output', 'low_box_power_stick', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('static-squat-jump-to-box', 'output', 'concentric_box_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('pause-box-jump', 'output', 'concentric_box_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('no-arm-swing-box-jump', 'output', 'concentric_box_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('box-jump-with-altitude-landing', 'resilience', 'landing_braking_control', 5, FALSE, 3, 3, 4, 4, 'moderate'),
  ('countermovement-box-jump', 'output', 'box_jump_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('athletic-box-jump-for-height-quality', 'output', 'box_jump_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('seated-start-box-jump', 'output', 'concentric_box_power', 5, TRUE, 5, 4, 4, 3, 'high'),
