INSERT INTO coaching.exercise_difficulty_profile (
  exercise_id, technical, load, complexity, overall,
  recommended_age_min, recommended_age_max, attention_demand, notes, source
)
SELECT e.id, 7, 7, 6, 7,
  9, NULL::integer, 'high', 'Advanced box-jump variation; use lower progression if landing quality or confidence is not present.', 'derived'
FROM coaching.exercise e
WHERE e.slug = 'single-leg-depth-drop-to-stick'
